mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_company
    WHERE company_id = #{companyId}
      AND active = TRUE
)

SELECT p.part_id, p.category_id, c.category_name, p.part_name, p.model_name, p.manufacturer, p.part_code, p.estimated_price, p.safe_quantity, COALESCE(s.quantity, 0) AS current_stock_quantity, p.active FROM tb_pc_part p JOIN tb_part_category c ON c.company_id = p.company_id AND c.category_id = p.category_id LEFT JOIN tb_part_stock s ON s.company_id = p.company_id AND s.part_id = p.part_id WHERE p.company_id = #{companyId}
AND p.active = #{active}
AND p.category_id = #{categoryId}
AND ( p.part_name LIKE CONCAT('%', #{keyword}, '%') OR p.model_name LIKE CONCAT('%', #{keyword}, '%') OR p.manufacturer LIKE CONCAT('%', #{keyword}, '%') OR p.part_code LIKE CONCAT('%', #{keyword}, '%') OR c.category_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY p.part_id DESC LIMIT #{limit}
